public class Main {
    static class Node {
        int data;
        Node next;
        Node prev;

        Node(int data) {
            this.data = data;
        }
    }

    public static void main(String[] args) {
        Node first = new Node(10);
        Node second = new Node(20);
        Node third = new Node(30);

        first.next = second;
        second.prev = first;
        second.next = third;
        third.prev = second;

        System.out.print("Forward: ");
        Node current = first;
        while (current != null) {
            System.out.print(current.data + " ");
            current = current.next;
        }

        System.out.print("\nBackward: ");
        current = third;
        while (current != null) {
            System.out.print(current.data + " ");
            current = current.prev;
        }
    }
}

public class Main {
    static class Node {
        int data;
        Node next;
        Node prev;
        Node(int data) { this.data = data; }
    }

    static class DoublyLinkedList {
        Node head;

        void insertAtHead(int data) {
            Node newNode = new Node(data);
            newNode.next = head;
            if (head != null) {
                head.prev = newNode;
            }
            head = newNode;
        }

        void printForward() {
            Node current = head;
            while (current != null) {
                System.out.print(current.data + " ");
                current = current.next;
            }
            System.out.println();
        }
    }

    public static void main(String[] args) {
        DoublyLinkedList list = new DoublyLinkedList();
        list.insertAtHead(30);
        list.insertAtHead(20);
        list.insertAtHead(10);
        list.printForward();
    }
}

public class Main {
    static class Node {
        int data;
        Node next;
        Node prev;
        Node(int data) { this.data = data; }
    }

    static Node head;

    static void insertAtHead(int data) {
        Node newNode = new Node(data);
        newNode.next = head;
        if (head != null) head.prev = newNode;
        head = newNode;
    }

    static void deleteNode(Node node) {
        if (node.prev != null) {
            node.prev.next = node.next;
        } else {
            head = node.next; // node was the head
        }
        if (node.next != null) {
            node.next.prev = node.prev;
        }
    }

    static void printForward() {
        Node current = head;
        while (current != null) {
            System.out.print(current.data + " ");
            current = current.next;
        }
        System.out.println();
    }

    public static void main(String[] args) {
        insertAtHead(30);
        insertAtHead(20);
        Node middleNode = head; // this is the node holding 20
        insertAtHead(10);

        deleteNode(middleNode);
        printForward();
    }
}

